    62→// Enqueue styles and scripts
    63→function hone_landing_enqueue_assets() {
    64→    global $class_names;
    65→
    66→    $theme_version = wp_get_theme()->get('Version');
    67→    $theme_uri = get_template_directory_uri();
    68→
    69→    // Always load main.min.css - contains all common styles (reset, settings, parts)
    70→    wp_enqueue_style(
    71→        'hone-main-style',
    72→        $theme_uri . '/static/css/main.min.css',
    73→        array(),
    74→        $theme_version
    75→    );
    76→
    77→    // Early return if no class_names set
    78→    if (empty($class_names) || !is_array($class_names)) {
    79→        return;
    80→    }
    81→
    82→    // Check if this template has page-specific styles
    83→    $matches = array_intersect($class_names, HONE_PAGE_TEMPLATES);
    84→
    85→    // Load all matching page-specific styles in order
    86→    // This allows for layered styles (e.g., base 'mens-hrt-aol' + specific 'mens-hrt-aol-forbes')
    87→    if (!empty($matches)) {
    88→        $dependencies = array('hone-main-style'); // First match depends on main styles
    89→        
    90→        foreach ($matches as $matched_class) {
    91→            $css_file = get_template_directory() . '/static/css/pages/' . $matched_class . '.css';
    92→            if (file_exists($css_file)) {
    93→                wp_enqueue_style(
    94→                    'hone-page-' . $matched_class,
    95→                    $theme_uri . '/static/css/pages/' . $matched_class . '.css',
    96→                    $dependencies,
    97→                    $theme_version,
    98→                    'all'
    99→                );
   100→                // Make next stylesheet depend on this one to maintain load order
   101→                $dependencies = array('hone-page-' . $matched_class);
   102→            }
   103→        }
   104→    }
   105→    
   106→    // Enqueue main JavaScript (always loaded - contains trackQuizEvent)
   107→    wp_enqueue_script(
   108→        'hone-main-script',
   109→        $theme_uri . '/static/js/dist/combined.js',
   110→        array(),
   111→        $theme_version,
   112→        true
   113→    );
   114→}
   115→add_action('wp_enqueue_scripts', 'hone_landing_enqueue_assets');
   116→
   117→/**
   118→ * Register page-specific JavaScript bundles
   119→ * 
   120→ * These bundles are built with esbuild and include all dependencies
   121→ * (except jQuery which is loaded via WordPress).
   122→ * 
   123→ * Each bundle includes: Slick carousel + relevant utilities
   124→ * 
   125→ * Usage in templates:
   126→ *   wp_enqueue_script('hone-page-article-trt-new-copy');
   127→ */
   128→function hone_register_bundles() {
   129→    $theme_version = wp_get_theme()->get('Version');
   130→    $theme_uri = get_template_directory_uri();
   131→    $theme_dir = get_template_directory();
   132→    
   133→    // Register jQuery Migrate (dependency for Slick)
   134→    wp_register_script(
   135→        'jquery-migrate',
   136→        $theme_uri . '/static/js/dist/jquery-migrate-1.2.1.min.js',
   137→        array('jquery'),
   138→        '1.2.1',
   139→        true
   140→    );
   141→    
   142→    // Register Slick carousel
   143→    wp_register_script(
   144→        'slick-carousel',
   145→        $theme_uri . '/static/js/dist/slick.min.js',
   146→        array('jquery', 'jquery-migrate'),
   147→        '1.8.1',
   148→        true
   149→    );
   150→    
   151→    // Register each page bundle with jQuery, jQuery Migrate, and Slick as dependencies
   152→    foreach (HONE_PAGE_TEMPLATES as $page) {
   153→        $bundle_path = $theme_dir . '/static/js/dist/pages/' . $page . '.bundle.min.js';
   154→        $bundle_url = $theme_uri . '/static/js/dist/pages/' . $page . '.bundle.min.js';
   155→        if (file_exists($bundle_path)) {
   156→            wp_register_script(
   157→                'hone-page-' . $page,
   158→                $bundle_url,
   159→                array('jquery', 'jquery-migrate', 'slick-carousel'),
   160→                $theme_version,
   161→                true
   162→            );
   163→        }
   164→    }
   165→}
   166→add_action('wp_enqueue_scripts', 'hone_register_bundles', 5);
   167→
   168→// the current LPs had funky urls and we need to match them exactly so that the ads don't get reset
   169→// The pages in wp-admin need to be set with these specific slugs and cannot have a parent page.
   170→remove_filter('template_redirect', 'redirect_canonical');
   171→add_action('init', function() {
   172→    add_rewrite_rule('^overview/3/?$', 'index.php?pagename=overview-3', 'top');
   173→    add_rewrite_rule('^overview/3/hormone-optimization/?$', 'index.php?pagename=overview-3-hormone-optimization', 'top');    
   174→    add_rewrite_rule('^overview/3/rww/tiktok/?$', 'index.php?pagename=overview-tiktok', 'top');        
   175→});
   176→
   177→add_filter('query_vars', function($vars) {
   178→    $vars[] = 'pagename';
   179→    return $vars;
   180→});
   181→
   182→function get_query_string(){
   183→    $query_params = [];
   184→    foreach ($_GET as $key => $value) {
   185→        $query_params[$key] = sanitize_text_field($value);
   186→    }
   187→    return http_build_query($query_params);
   188→}
