/**
 * Modern Template
 * Article TRT
 */
@use '../variables/layout' as layout;
@use '../variables/colors' as colors;
@use '../variables/fonts' as fonts;

$color-gray-medium-transparent-80: rgba(96, 91, 82, 0.80);

main.article-trt {
	> *:not(.linkbar, .navbar, .site-footer) {
		max-width: 1440px;
		margin: 0 auto;
	}

	/** 
	* ------------------------------------------------------------
	* Sticky CTA
	* ------------------------------------------------------------
	*/
	.stickycta-section {
		visibility: hidden;
		background-color: rgba(14, 11, 32, 0.8);
		backdrop-filter: blur(15px);
		-webkit-backdrop-filter: blur(15px);
		position: fixed;
		z-index: 1000;
		width: calc(100% - 130px);
		left: 50%;
		transform: translateX(-50%);
		margin-bottom: 28px;
		border-radius: 20px;
		border: none;
		padding: fonts.rem(26px) 2rem;
		bottom: 0;
		max-width: calc(1440px - 130px);
		@media only screen and (max-width: 1024px) {
			width: calc(100% - 80px);
		}
		@media only screen and (max-width: 690px) {
			padding: fonts.rem(12px);
			border-radius: 15px;
		}
		@media #{layout.$small-screen-only} {
			width: calc(100% - 32px);
		}
		&.show {
			visibility: visible;
		}
		.container {
			display: flex;
			justify-content: space-between;
			align-items: center;
			gap: fonts.rem(12px);
			@media only screen and (max-width: 690px) {
				flex-direction: column;
			}
			.title-block {
				font-family: fonts.$DM-Sans;
				font-weight: 400;
				font-style: Regular;
				font-size: fonts.rem(16px);
				line-height: 140%;
				letter-spacing: -1%;
				color: #fff;
				margin: 0;
				display: flex;
				flex-direction: column;
				gap: 0.5rem;
				@media only screen and (max-width: 690px) {
					width: 100%;
				}
				.pricing-block {
					display: flex;
					align-items: center;
					flex-wrap: wrap;
					gap: 0.5rem;
					color: colors.$color-white;
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(16px);
					font-weight: 400;
					line-height: 140%;
					letter-spacing: -0.16px;
					@media only screen and (max-width: 690px) {
						color: colors.$color-white;
						font-family: fonts.$DM-Sans;
						font-size: fonts.rem(14px);
						font-weight: 400;
						line-height: 140%;
						letter-spacing: -0.14px;
					}
					.price {
						color: colors.$color-white;
						font-family: fonts.$Azeret-Mono;
						font-size: fonts.rem(18px);
						font-weight: 400;
						line-height: 120%;
					}	
				}
				.availability { 
					color: colors.$color-white;
					font-family: fonts.$DM-Sans;
