			padding: 2.5rem;
			grid-template-columns: 1fr;
			grid-template-rows: auto auto auto;
			grid-template-areas: "sidebar"
				"content1"
				"content2"
				"content3";
			gap: 1.5rem;
		}
		@media #{layout.$small-screen-only} {
			padding: 2.5rem 1rem;
		}

		/*
		* =============================
		* Sidebar
		* =============================
		*/
		.sidebar-wrapper {
			grid-area: sidebar;
			position: sticky;
			top: 64px;
			height: fit-content;
			align-self: start;
			@media #{layout.$medium-screen-and-smaller} {
				position: static;
				top: auto;
			}

			&.is-stuck {
				position: fixed;
