				width: 310px;
				transition: top 0.5s ease;

				@media #{layout.$medium-screen-and-smaller} {
					position: static;
					width: auto;
				}
			}

			&.is-bottom {
				position: absolute;
				bottom: 0;
				top: auto;

				@media #{layout.$medium-screen-and-smaller} {
					position: static;
					bottom: auto;
				}
			}

			.sidebar-block {
				gap: 1.5rem;
