			}
			.nav-dots {
				@media #{layout.$small-screen-only} {
					gap: fonts.rem(4px);
				}
				.nav-dot {
					// Hide dots 11+ on desktop (1025px+) where 3 slides are shown
					&.hide-desktop {
						@media #{layout.$large-screen-and-larger} {
							display: none;
						}
					}
					// Hide dots 12+ on medium screens (601px+) where 2+ slides are shown
					&.hide-medium {
						@media #{layout.$medium-screen-and-larger} {
							display: none;
						}
					}
				}
			}
		}
	}
}

