/**
 * Modern Template
 * Article TRT New Copy
 */
@use '../variables/layout' as layout;
@use '../variables/colors' as colors;
@use '../variables/fonts' as fonts;

$color-gray-medium-transparent-80: rgba(96, 91, 82, 0.80);
$color-gray-night-80: rgba(14, 11, 32, 0.80);
$color-gray-medium-60: #6D6D6D;


main.article-trt-new-copy {
	> *:not(.linkbar, .navbar, .site-footer, .customized-care-plans, .testimonials) {
		max-width: 1440px;
		margin: 0 auto;
	}

	/** 
	* ------------------------------------------------------------
	* Sticky CTA
	* ------------------------------------------------------------
	*/
	.stickycta-section {
		visibility: hidden;
		background-color: rgba(14, 11, 32, 0.8);
		backdrop-filter: blur(15px);
		-webkit-backdrop-filter: blur(15px);
		position: fixed;
		z-index: 1000;
		width: calc(100% - 130px);
		left: 50%;
		transform: translateX(-50%);
		margin-bottom: 28px;
		border-radius: 20px;
		border: none;
		padding: fonts.rem(26px) 2rem;
		bottom: 0;
		max-width: calc(1440px - 130px);
		@media only screen and (max-width: 1024px) {
			width: calc(100% - 80px);
		}
		@media only screen and (max-width: 690px) {
			padding: fonts.rem(12px);
			border-radius: 15px;
		}
		@media #{layout.$small-screen-only} {
			width: calc(100% - 32px);
		}
		&.show {
			visibility: visible;
		}
		.container {
			display: flex;
			justify-content: space-between;
			align-items: center;
			gap: fonts.rem(12px);
			@media only screen and (max-width: 690px) {
				flex-direction: column;
			}
			.title-block {
				font-family: fonts.$DM-Sans;
				font-weight: 400;
				font-style: Regular;
				font-size: fonts.rem(16px);
				line-height: 140%;
				letter-spacing: -1%;
				color: #fff;
				margin: 0;
				display: flex;
				flex-direction: column;
				gap: 0.5rem;
				@media only screen and (max-width: 690px) {
					width: 100%;
				}
				.pricing-block {
					display: flex;
					align-items: center;
					flex-wrap: wrap;
					gap: 0.5rem;
					color: colors.$color-white;
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(16px);
					font-weight: 400;
					line-height: 140%;
					letter-spacing: -0.16px;
					@media only screen and (max-width: 690px) {
						color: colors.$color-white;
						font-family: fonts.$DM-Sans;
						font-size: fonts.rem(14px);
						font-weight: 400;
						line-height: 140%;
						letter-spacing: -0.14px;
					}
					.price {
						color: colors.$color-white;
						font-family: fonts.$Azeret-Mono;
						font-size: fonts.rem(18px);
						font-weight: 400;
						line-height: 120%;
					}	
				}
				.availability { 
					color: colors.$color-white;
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(14px);
					font-style: normal;
					font-weight: 400;
					line-height: 140%;
					letter-spacing: -0.14px;
					.availability-text {
						background-color: #605B5299;
						padding: 0 4px;
						color: colors.$color-white;
						font-family: fonts.$DM-Sans;
						font-size: fonts.rem(14px);
						font-weight: 400;
						line-height: 140%;
						letter-spacing: -1%;
						border-radius: 4px;
					}
					.availability-text::before {
						content: '';
						width: 8px;
						height: 8px;
						background-color: #20C475;
						border-radius: 50%;
						display: inline-block;
						margin-right: 4px;
					}
				}
			}
			.cta-block {
				@media only screen and (max-width: 690px) {
					width: 100%;
				}
				.cta-wrapper {
					width: 100%;
					a {
						width: 100%;
					}
					.btn {
						width: auto;
						padding: fonts.rem(15px) fonts.rem(26px);
					}
				}
			}
		}
	}

	/*
	* =============================
	* Linkbar
	* =============================
	*/
	.linkbar {
		a {
			display: flex;
			gap: 1.5rem;
			justify-content: center;
			align-items: center;
			@media #{layout.$small-screen-only} {
				flex-direction: column;
				gap: 0;
			}
			.linkbar-button {
				display: flex;
				gap: 0.5rem;
				align-items: center;
				span {
					color: colors.$color-black;
					font-variant-numeric: slashed-zero;
					font-feature-settings: 'dlig' on, 'ss02' on;
					font-family: fonts.$DM-Sans;
					font-size: 1rem;
					font-weight: 500;
					line-height: 130%;
					letter-spacing: -0.32px;
				}
				img {
					width: 11.89px;
					height: 11.89px;
				}
			}
		}
	}

	/*
	* =============================
	* Title Section
	* =============================
	*/
	.title-section {
		gap: 1rem;
		padding: 2.5rem 4rem 0;
		@media #{layout.$medium-screen-and-smaller} {
			padding: 2.5rem 2.5rem 0;
		}
		@media #{layout.$small-screen-only} {
			padding: 2.5rem 1rem 0;
		}
		.text-wrapper {
			margin-bottom: 2rem;
			gap: 1rem;
			.duration {
				color: colors.$color-gray;
				font-family: fonts.$Azeret-Mono;
				font-size: 1rem;
				font-weight: 400;
				line-height: 120%;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: 0.75rem;
				}
			}
			.title-block {
				gap: 1rem;
				h2 {
					color: colors.$color-black;
					font-family: fonts.$STIX-Two-Text;
					font-size: 3.625rem;
					font-weight: 400;
					line-height: 100%;
					letter-spacing: -1.16px;
					@media #{layout.$medium-screen-and-smaller} {
						font-size: 2.25rem;
						letter-spacing: -0.72px;
					}
				}
				p {
					color: colors.$color-gray-dark;
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(22px);
					font-style: normal;
					font-weight: 500;
					line-height: 110%;
					letter-spacing: -0.44px;
					@media #{layout.$medium-screen-and-smaller} {
						font-size: 1.125rem;
						letter-spacing: -0.36px;
					}
				}
			}
		}
		.media-wrapper {
			img {
				border-radius: 15px;
			}
		}
	}

		/*
	* =============================
	* Content Section
	* =============================
	*/
	.content-section {
		position: relative;
		display: grid;
		padding: 4rem 4rem 2.5rem 4rem;
		grid-template-columns: 310px 1fr;
		grid-template-rows: auto auto auto;
		gap: 0 4rem;
		@media #{layout.$medium-screen-and-smaller} {
			padding: 2.5rem;
			grid-template-columns: 1fr;
			grid-template-areas: "sidebar"
				"content1"
				"content2"
				"content3";
			gap: 1.5rem;
		}
		@media #{layout.$small-screen-only} {
			padding: 2.5rem 1rem;
		}
		&.section-1 {
			padding-inline: 4rem;

			grid-template-areas: "sidebar content1"
				"sidebar content2"
				"sidebar content3";
			@media #{layout.$medium-screen-and-smaller} {
				padding: 2.5rem;
				grid-template-columns: 1fr;
				grid-template-areas: "sidebar"
					"content1"
					"content2"
					"content3";
				gap: 1.5rem;
			}
			@media #{layout.$small-screen-only} {
				padding-inline: 1rem;
			}
		}
		&.section-2,
		&.section-3 {
			padding-bottom: fonts.rem(64px);
			@media #{layout.$medium-screen-and-smaller} {
				grid-template-areas:
					"content4";
				gap: 0;
				padding-bottom: fonts.rem(40px);
			}
		}
		&.section-2 {
			grid-template-areas: "sidebar content4";
			@media #{layout.$medium-screen-and-smaller} {
				grid-template-areas:
					"content4";
			}
		}
		&.section-3 {
			grid-template-areas: "sidebar content5";
			@media #{layout.$medium-screen-and-smaller} {
				grid-template-areas:
					"content5";
			}
		}
	}

	/*
	* =============================
	* Sidebar
	* =============================
	*/
	.sidebar-wrapper {
		grid-area: sidebar;
		position: sticky;
		top: 64px;
		height: fit-content;
		align-self: start;
		@media #{layout.$medium-screen-and-smaller} {
			position: static;
			top: auto;
		}
		&.is-stuck {
			position: fixed;
			top: 64px;
			width: 310px;
			transition: top 0.5s ease;

			@media #{layout.$medium-screen-and-smaller} {
				position: static;
				width: auto;
			}
		}
		&.is-bottom {
			position: absolute;
			bottom: 0;
			top: auto;

			@media #{layout.$medium-screen-and-smaller} {
				position: static;
				bottom: auto;
			}
		}
		.sidebar-block {
			gap: 1.5rem;
			.title-block {
				color: colors.$color-black;
				font-family: fonts.$DM-Sans;
				font-size: 0.875rem;
				font-weight: 700;
				line-height: 110%;
				letter-spacing: -0.28px;
			}
			.anchor-list {
				gap: 1rem;
				border-left: 1px solid colors.$color-gray-medium;
				a {
					position: relative;
					display: block;
					margin-left: -1px;
					padding-left: calc(0.75rem + 1px);
					border-left: 1px solid transparent;
					transition: border-color 0.5s ease, color 0.5s ease;
					color: #000;
					font-variant-numeric: slashed-zero;
					font-feature-settings: 'dlig' on, 'ss02' on;
					font-family: fonts.$DM-Sans;
					font-size: 1rem;
					font-style: normal;
					font-weight: 500;
					line-height: 130%;
					letter-spacing: -0.32px;
					&.active {
						border-left: 1px solid colors.$color-black;
					}
					&:first-child {
						@media #{layout.$medium-screen-and-smaller} {
							border-left: 1px solid colors.$color-black;
						}
					}
				}
			}
		}
	}
	/*
	* =============================
	* Content Wrapper
	* =============================
	*/
	.content-wrapper {
		display: flex;
		flex-direction: column;
		gap: 1rem;
		margin-bottom: 2.5rem;
		@media #{layout.$medium-screen-and-smaller} {
			margin-bottom: 1.5rem;
		}
		p, 
		ul,
		ol {
			color: colors.$color-black;
			font-family: fonts.$DM-Sans;
			font-size: 1rem;
			font-weight: 400;
			line-height: 140%;
			letter-spacing: -0.16px;
			@media #{layout.$medium-screen-and-smaller} {
				font-size: 0.875rem;
				letter-spacing: -0.14px;
			}
		}
		ul {
			display: flex;
			flex-direction: column;
			gap: 0.75rem;
			margin-left: 1.5rem;
			@media #{layout.$medium-screen-and-smaller} {
				margin-left: 0;
			}
		}
		li {
			display: flex;
			align-items: start;
			gap: 5px;
			&::before {
				content: "•";
				color: colors.$color-black;
				font-size: fonts.rem(20px);
				line-height: 105%;
			}
		}
		h3 {
			color: colors.$color-black;
			font-family: fonts.$STIX-Two-Text;
			font-size: 2.25rem;
			font-weight: 400;
			line-height: 100%;
			letter-spacing: -0.72px;
			@media #{layout.$medium-screen-and-smaller} {
				font-size: 1.8125rem;
				line-height: 96%;
				letter-spacing: -0.29px;
			}
		}
	}
	.block-wrapper {
		display: grid;
		grid-template-columns: 1fr 1fr;
		background-color: colors.$color-gray-light;
		margin-top: 4rem;
		margin-bottom: 2.5rem;
		@media #{layout.$medium-screen-and-smaller} {
			margin-top: 2.5rem;
			margin-bottom: 1.5rem;
		}
		@media #{layout.$small-screen-only} {
			grid-template-columns: 1fr;
		}
		&.dark-background {
			background-color: colors.$color-gray-light;
		}
		&.light-background {
			background-color: colors.$color-white;
		}
		.media-block {
			min-height: 404px;
			@media #{layout.$small-screen-only} {
				height: 254px;
				min-height: unset;
			}
			img {
				object-fit: cover;
				object-position: center;
				width: 100%;
				height: 100%;
			}
		}
		.content-block {
			padding: 2.5rem;
			border: 2px solid colors.$color-gray-medium-transparent;
			border-left: none;
			display: flex;
			flex-direction: column;
			gap: 0.75rem;
			@media #{layout.$small-screen-only} {
				padding: 1rem;
				border-left: 2px solid colors.$color-gray-medium-transparent;
				border-top: none;
			}
			h3 {
				color: colors.$color-black;
				font-family: fonts.$DM-Sans;
				font-size: 1.75rem;
				font-weight: 400;
				line-height: 110%;
				letter-spacing: -0.56px;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: 1.375rem;
					font-weight: 500;
					letter-spacing: -0.44px;
				}
			}
			p, 
			ul {
				color: colors.$color-gray-dark;
				font-family: fonts.$DM-Sans;
				font-size: 1rem;
				font-weight: 400;
				line-height: 140%;
				letter-spacing: -0.16px;
				margin-bottom: 1.5rem;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: 0.875rem;
					line-height: 140%;
					letter-spacing: -0.14px;
				}
			}
			ul {
				display: flex;
				flex-direction: column;
				gap: 0.75rem;
				margin-left: 1.5rem;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: 0.875rem;
					letter-spacing: -0.14px;
				}
			}
			li {
				display: flex;
				align-items: start;
				gap: 5px;
				&::before {
					content: "•";
					color: colors.$color-gray-dark;
					font-size: fonts.rem(20px);
					line-height: 105%;
				}
			}
			.paragraph-block {
				flex: 1;
			}
