const fs = require('fs-extra');
const path = require('path');
const { execSync } = require('child_process');

// Paths
const srcDir = path.resolve(__dirname, 'src');
const buildDir = path.resolve(__dirname, 'build');

// Helper function to run shell commands
function runCommand(command) {
  try {
    console.log(`Running: ${command}`);
    execSync(command, { stdio: 'inherit' });
  } catch (error) {
    console.error(`Error running command: ${command}`);
    process.exit(1);
  }
}

// Clean the build directory
console.log('Cleaning build directory...');
fs.emptyDirSync(buildDir);

// Run asset build steps
console.log('Building CSS/JS assets...');
runCommand('yarn build:assets');

// Copy theme files (excluding scss, static/js/index.js, and static/js/modules directory)
console.log('Copying theme files...');
fs.copySync(srcDir, buildDir, {
  filter: (src) => {
    const normalizedSrc = path.normalize(src);

    return (
      !normalizedSrc.endsWith('.scss') &&
      !normalizedSrc.includes(path.join('static', 'scss')) &&
      !normalizedSrc.includes(path.join('static', 'js', 'modules')) &&
      !normalizedSrc.endsWith(path.join('static', 'js', 'index.js'))
    );
  },
});

console.log('Build complete!');
